     1→<!DOCTYPE html>
     2→<html lang="zh-CN">
     3→<head>
     4→    <meta charset="UTF-8">
     5→    <meta name="viewport" content="width=device-width, initial-scale=1.0">
     6→    <title>简单计算器</title>
     7→    <style>
     8→        * {
     9→            margin: 0;
    10→            padding: 0;
    11→            box-sizing: border-box;
    12→        }
    13→
    14→        body {
    15→            min-height: 100vh;
    16→            display: flex;
    17→            justify-content: center;
    18→            align-items: center;
    19→            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    20→            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    21→        }
    22→
    23→        .calculator {
    24→            background: #fff;
    25→            border-radius: 20px;
    26→            box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
    27→            padding: 30px;
    28→            width: 320px;
    29→        }
    30→
    31→        .display {
    32→            width: 100%;
    33→            height: 60px;
    34→            background: #1a1a2e;
    35→            border: none;
    36→            border-radius: 10px;
    37→            color: #fff;
    38→            font-size: 28px;
    39→            text-align: right;
    40→            padding: 15px;
    41→            margin-bottom: 20px;
    42→            outline: none;
    43→        }
    44→
    45→        .buttons {
    46→            display: grid;
    47→            grid-template-columns: repeat(4, 1fr);
    48→            gap: 10px;
    49→        }
    50→
    51→        button {
    52→            padding: 20px;
    53→            font-size: 20px;
    54→            border: none;
    55→            border-radius: 10px;
    56→            cursor: pointer;
    57→            transition: all 0.2s;
    58→            background: #f0f0f0;
    59→            color: #333;
    60→        }
    61→
    62→        button:hover {
    63→            transform: scale(1.05);
    64→        }
    65→
    66→        button:active {
    67→            transform: scale(0.95);
    68→        }
    69→
    70→        .btn-number {
    71→            background: #fff;
    72→            box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
    73→        }
    74→
    75→        .btn-operator {
    76→            background: #667eea;
    77→            color: #fff;
    78→        }
    79→
    80→        .btn-equal {
    81→            background: #764ba2;
    82→            color: #fff;
    83→            grid-column: span 2;
    84→        }
    85→
    86→        .btn-clear {
    87→            background: #ff6b6b;
    88→            color: #fff;
    89→        }
    90→    </style>
    91→</head>
    92→<body>
    93→    <div class="calculator">
    94→        <input type="text" class="display" id="display" readonly>
    95→        <div class="buttons">
    96→            <button class="btn-clear" onclick="clearDisplay()">C</button>
    97→            <button class="btn-operator" onclick="deleteChar()">⌫</button>
    98→            <button class="btn-operator" onclick="appendOperator('/')">÷</button>
    99→            <button class="btn-operator" onclick="appendOperator('*')">×</button>
   100→
   101→            <button class="btn-number" onclick="appendNumber('7')">7</button>
   102→            <button class="btn-number" onclick="appendNumber('8')">8</button>
   103→            <button class="btn-number" onclick="appendNumber('9')">9</button>
   104→            <button class="btn-operator" onclick="appendOperator('-')">-</button>
   105→
   106→            <button class="btn-number" onclick="appendNumber('4')">4</button>
   107→            <button class="btn-number" onclick="appendNumber('5')">5</button>
   108→            <button class="btn-number" onclick="appendNumber('6')">6</button>
   109→            <button class="btn-operator" onclick="appendOperator('+')">+</button>
   110→
   111→            <button class="btn-number" onclick="appendNumber('1')">1</button>
   112→            <button class="btn-number" onclick="appendNumber('2')">2</button>
   113→            <button class="btn-number" onclick="appendNumber('3')">3</button>
   114→            <button class="btn-equal" onclick="calculate()">=</button>
   115→
   116→            <button class="btn-number" onclick="appendNumber('0')" style="grid-column: span 2;">0</button>
   117→            <button class="btn-number" onclick="appendNumber('.')">.</button>
   118→        </div>
   119→    </div>
   120→
   121→    <script>
   122→        const display = document.getElementById('display');
   123→
   124→        function appendNumber(num) {
   125→            if (display.value === '0' && num !== '.') {
   126→                display.value = num;
   127→            } else {
   128→                display.value += num;
   129→            }
   130→        }
   131→
   132→        function appendOperator(op) {
   133→            const lastChar = display.value.slice(-1);
   134→            if (['+', '-', '*', '/'].includes(lastChar)) {
   135→                display.value = display.value.slice(0, -1) + op;
   136→            } else {
   137→                display.value += op;
   138→            }
   139→        }
   140→
   141→        function clearDisplay() {
   142→            display.value = '0';
   143→        }
   144→
   145→        function deleteChar() {
   146→            if (display.value.length === 1) {
   147→                display.value = '0';
   148→            } else {
   149→                display.value = display.value.slice(0, -1);
   150→            }
   151→        }
   152→
   153→        function calculate() {
   154→            try {
   155→                const result = eval(display.value);
   156→                if (result === Infinity || isNaN(result)) {
   157→                    display.value = '错误';
   158→                } else {
   159→                    display.value = result;
   160→                }
   161→            } catch (e) {
   162→                display.value = '错误';
   163→            }
   164→        }
   165→
   166→        // 键盘支持
   167→        document.addEventListener('keydown', (e) => {
   168→            if (e.key >= '0' && e.key <= '9' || e.key === '.') {
   169→                appendNumber(e.key);
   170→            } else if (e.key === '+' || e.key === '-') {
   171→                appendOperator(e.key);
   172→            } else if (e.key === '*') {
   173→                appendOperator('*');
   174→            } else if (e.key === '/') {
   175→                e.preventDefault();
   176→                appendOperator('/');
   177→            } else if (e.key === 'Enter' || e.key === '=') {
   178→                calculate();
   179→            } else if (e.key === 'Escape') {
   180→                clearDisplay();
   181→            } else if (e.key === 'Backspace') {
   182→                deleteChar();
   183→            }
   184→        });
   185→    </script>
   186→</body>
   187→</html>
